def validate(args, output):
    a, b = args[0], args[1]
    if not isinstance(output, str):
        return False
    if len(output) != a + b:
        return False
    if output.count('a') != a or output.count('b') != b:
        return False
    if set(output) - {'a', 'b'}:
        return False
    if 'aaa' in output or 'bbb' in output:
        return False
    return True

