function validate(args, output) {
    const a = args[0], b = args[1];
    if (typeof output !== 'string') return false;
    if (output.length !== a + b) return false;
    let ca = 0, cb = 0;
    for (const ch of output) {
        if (ch === 'a') ca++;
        else if (ch === 'b') cb++;
        else return false;
    }
    if (ca !== a || cb !== b) return false;
    if (output.includes('aaa') || output.includes('bbb')) return false;
    return true;
}

