class Solution:
    def strWithout3a3b(self, a, b):
        res = []
        while a > 0 or b > 0:
            if len(res) >= 2 and res[-1] == res[-2]:
                use_a = res[-1] == 'b'
            else:
                use_a = a >= b
            if use_a and a > 0:
                res.append('a')
                a -= 1
            elif not use_a and b > 0:
                res.append('b')
                b -= 1
            elif a > 0:
                res.append('a')
                a -= 1
            else:
                res.append('b')
                b -= 1
        return ''.join(res)

