        res = []
        while a > 0 or b > 0:
            tail = ''.join(res[-2:])
            if tail == 'aa':
                pick = 'b'
            elif tail == 'bb':
                pick = 'a'
            elif a >= b:
                pick = 'a'
            else:
                pick = 'b'
            if pick == 'a' and a == 0:
                pick = 'b'
            if pick == 'b' and b == 0:
                pick = 'a'
            if pick == 'a':
                res.append('a')
                a -= 1
