var strWithout3a3b = function(a, b) {
    const res = [];
    while (a > 0 || b > 0) {
        const tail = res.slice(-2).join('');
        let pick;
        if (tail === 'aa') pick = 'b';
        else if (tail === 'bb') pick = 'a';
        else if (a >= b) pick = 'a';
        else pick = 'b';
        if (pick === 'a' && a === 0) pick = 'b';
        if (pick === 'b' && b === 0) pick = 'a';
        if (pick === 'a') { res.push('a'); a--; }
        else { res.push('b'); b--; }
    }
    return res.join('');
};
